package com.oneil.wellness.walkplanner.data;import jakarta.persistence.*;import java.time.Instant;@Entity@Table(name="history_retention_settings")public class HistoryRetention{@Id private short id=1;@Column(name="recommendation_days")private Integer recommendationDays;@Column(name="notification_days")private Integer notificationDays;@Column(name="expired_outcome_days")private Integer expiredOutcomeDays;@Column(name="activity_days")private Integer activityDays;@Column(name="updated_at",nullable=false)private Instant updatedAt;protected HistoryRetention(){}public HistoryRetention(HistoryRetentionRequest r){update(r);}public void update(HistoryRetentionRequest r){recommendationDays=r.recommendationDays();notificationDays=r.notificationDays();expiredOutcomeDays=r.expiredOutcomeDays();activityDays=r.activityDays();updatedAt=Instant.now();}public Integer getRecommendationDays(){return recommendationDays;}public Integer getNotificationDays(){return notificationDays;}public Integer getExpiredOutcomeDays(){return expiredOutcomeDays;}public Integer getActivityDays(){return activityDays;}}
